package apperror

import (
    "fmt"
    "net/http"
)

type AppError struct {
    Code       string `json:"code"`
    Message    string `json:"message"`
    HTTPStatus int    `json:"-"`
    Err        error  `json:"-"`
}

func (e *AppError) Error() string {
    if e.Err != nil {
        return fmt.Sprintf("%s: %v", e.Message, e.Err)
    }
    return e.Message
}

func (e *AppError) Unwrap() error { return e.Err }

// Constructor functions — never return package-level vars directly.
// Mutable package vars are a footgun: ErrNotFound.Message = "X" mutates the global.

func NewNotFound(resource string) *AppError {
    return &AppError{
        Code:       "NOT_FOUND",
        Message:    fmt.Sprintf("%s not found", resource),
        HTTPStatus: http.StatusNotFound,
    }
}

func NewUnauthorized(msg string) *AppError {
    return &AppError{Code: "UNAUTHORIZED", Message: msg, HTTPStatus: http.StatusUnauthorized}
}

func NewValidation(msg string) *AppError {
    return &AppError{Code: "VALIDATION_ERROR", Message: msg, HTTPStatus: http.StatusBadRequest}
}

// Wrap preserves HTTPStatus and Code from inner *AppError when present.
func Wrap(err error, msg string) *AppError {
    var inner *AppError
    if errors.As(err, &inner) {
        return &AppError{
            Code:       inner.Code,
            Message:    msg,
            HTTPStatus: inner.HTTPStatus,
            Err:        err,
        }
    }
    return &AppError{
        Code:       "INTERNAL_ERROR",
        Message:    msg,
        HTTPStatus: http.StatusInternalServerError,
        Err:        err,
    }
}

package httpx

import (
    "encoding/json"
    "errors"
    "log/slog"
    "net/http"

    "yourmod/pkg/apperror"
)

type errBody struct {
    Code    string `json:"code"`
    Message string `json:"message"`
    TraceID string `json:"trace_id,omitempty"`
}

type Handler func(http.ResponseWriter, *http.Request) error

func Wrap(h Handler) http.HandlerFunc {
    return func(w http.ResponseWriter, r *http.Request) {
        err := h(w, r)
        if err == nil {
            return
        }
        var appErr *apperror.AppError
        if !errors.As(err, &appErr) {
            appErr = apperror.Wrap(err, "internal error")
        }
        // 4xx → Info/Warn, 5xx → Error
        if appErr.HTTPStatus >= 500 {
            slog.ErrorContext(r.Context(), "http error",
                "code", appErr.Code, "status", appErr.HTTPStatus, "err", err)
        } else {
            slog.InfoContext(r.Context(), "http client error",
                "code", appErr.Code, "status", appErr.HTTPStatus)
        }
        w.Header().Set("Content-Type", "application/json")
        w.WriteHeader(appErr.HTTPStatus)
        _ = json.NewEncoder(w).Encode(errBody{
            Code: appErr.Code, Message: appErr.Message,
            TraceID: TraceIDFromCtx(r.Context()),
        })
    }
}
